-- Seed the 11 industry sector row-cards as published industry_sector CMS entries,
-- extracted verbatim from industries.html .industry-grid (tools-side parser). Mirrors the
-- hardcoded fallback so the admin CMS owns them and Supabase-backed builds keep emitting
-- industry-sectors.json. sort_order preserves the curated DOM order; image_w/image_h reserve
-- layout (CLS); the "View fit" target is derived from slug at render time. Idempotent.
-- Apply via the pooled service-role connection.

on conflict (type, slug, locale) do update
  set title = excluded.title, status = excluded.status, payload = excluded.payload,
      seo = excluded.seo, published_at = coalesce(public.content_entries.published_at, now()), updated_at = now();

update public.content_entries set published_at = coalesce(published_at, now())
  where type = 'industry_sector' and status = 'published';
